package com.zut.librarynet.config;import com.google.auth.oauth2.GoogleCredentials;import com.google.cloud.firestore.Firestore;import com.google.firebase.FirebaseApp;import com.google.firebase.FirebaseOptions;import com.google.firebase.cloud.FirestoreClient;import java.io.InputStream;public class FirebaseConfig{public static void initialize(){try{InputStream serviceAccount=FirebaseConfig.class.getClassLoader().getResourceAsStream("firebase-service-account.json");if(serviceAccount==null){throw new RuntimeException("Firebase JSON file not found!");}FirebaseOptions options=FirebaseOptions.builder().setCredentials(GoogleCredentials.fromStream(serviceAccount)).build();if(FirebaseApp.getApps().isEmpty()){FirebaseApp.initializeApp(options);System.out.println("Firebase initialized successfully!");}}catch(Exception e){e.printStackTrace();}}public static Firestore getFirestore(){return FirestoreClient.getFirestore();}}
